mapper.select:
SELECT menu_name
FROM review_menu_tbl
WHERE review_no = (SELECT review_no
                   FROM review_tbl
                   WHERE rest_no = #{restNo}
);

SELECT r.review_no, m.member_name AS writer, m.member_thumb AS writer_thumb, r.rating, r.review_content, r.visit_date
FROM review_tbl r INNER JOIN member_tbl m ON r.member_no = m.member_no WHERE rest_no = #{restNo} ORDER BY r.visit_date DESC
LIMIT #{size} OFFSET #{offset}
